request.query:
BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?req ?reqName ?propName ?propValue WHERE {
  ?req rdf:type vocab:tmt%20requirement .
  ?req vocab:NamedElement_name ?reqName .
  FILTER(CONTAINS(LCASE(STR(?reqName)), LCASE("APS")))
  OPTIONAL {
    ?req vocab:Slot_value ?propValue .
    ?req vocab:NamedElement_name ?propName .
  }
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?dcName ?spec ?min ?max ?expr WHERE {
  ?dc rdf:type vocab:duration%20constraint .
  ?dc vocab:NamedElement_name ?dcName .
  FILTER(CONTAINS(LCASE(STR(?dcName)), LCASE("APS")) || 
         CONTAINS(LCASE(STR(?dcName)), LCASE("apt")) ||
         CONTAINS(LCASE(STR(?dcName)), LCASE("pit")) ||
         CONTAINS(LCASE(STR(?dcName)), LCASE("sh")) ||
         CONTAINS(LCASE(STR(?dcName)), LCASE("peas")))
  OPTIONAL { ?dc vocab:DurationConstraint_specification__from_DurationConstraint ?spec }
  OPTIONAL { ?spec vocab:DurationInterval_min__from_DurationInterval ?min }
  OPTIONAL { ?spec vocab:DurationInterval_max__from_DurationInterval ?max }
  OPTIONAL { ?min vocab:Duration_expr ?exprMin }
  OPTIONAL { ?max vocab:Duration_expr ?exprMax }
}
LIMIT 50
